UPDATE TBOT_POINT_NEW_BOSS
   SET HP        = #{newHp, jdbcType=NUMERIC}
     , END_YN    = #{endYn, jdbcType=VARCHAR}
     , PROC_DATE = SYSDATE

     , DEBUFF = DEBUFF + 10


     , DEBUFF = DEBUFF - 1


     , DEBUFF1 = DEBUFF1 + 5


     , DEBUFF1 = DEBUFF1 - 1

 WHERE SEQ    = #{seq, jdbcType=NUMERIC}
   AND HP     = #{hp, jdbcType=NUMERIC}
   AND END_YN = '0'
